using namespace std;
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    string line;
    getline(cin, line); // consume end-of-line after T
    for (int i = 0; i < T; ++i) {
        getline(cin, line); // discard dummy line
        cout << "CIVVIC";
        if (i + 1 < T) cout << '\n';
    }
    return 0;
}

code.Java:
import java.io.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String first = br.readLine();
        if (first == null) return;
        int T = Integer.parseInt(first.trim());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            br.readLine(); // discard dummy line
            sb.append("CIVVIC");
            if (i + 1 < T) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

